class ECHKeys:
    """A real ECHConfig and its private key, generated by `openssl ech` (RFC 9849)."""

    def __init__(self, directory, public_name: str = "public.example"):
        self.openssl = Authority.locate()
        self.pemfile = os.path.join(str(directory), "ech.pem")
        self.public_name = public_name

        result = subprocess.run([self.openssl, "ech", "-public_name", public_name, "-out", self.pemfile], capture_output=True)

        if result.returncode != 0:
            raise RuntimeError(f"{self.openssl} ech failed with exit code {result.returncode}:\n{result.stderr.decode(errors='replace')}")

    @property
    def configlist(self) -> bytes:
        """The raw ECHConfigList bytes, as a client would receive them from a DNS HTTPS record."""

        import base64

        with open(self.pemfile) as f:
            pem = f.read()

        block = pem.split("-----BEGIN ECHCONFIG-----")[1].split("-----END ECHCONFIG-----")[0]
        return base64.b64decode(block)

@pytest.fixture(scope="session")
def ech_keys(tmp_path_factory):
    from kaede.tls.openssl import OpenSSL

    if OpenSSL().set_ech_config_list is None:
        pytest.skip("ECH needs OpenSSL 4.0 or newer")

    return ECHKeys(tmp_path_factory.mktemp("ech"))
